def trimmed_mean(nums):
    if not nums:
        return None
    nums.sort()
    median = len(nums) // 2
    if len(nums) % 2 == 0:
        min_index, max_index = median - 1, median
    else:
        min_index, max_index = median, median + 1
    mean = sum(nums[min_index+1:max_index]) / (max_index - min_index - 1)
    return mean
